const items = $input.all();
const results = [];

for (const item of items) {
    let texto = item.json.response || "";
    let minuta = "No se pudo extraer el texto de la minuta";
    let datos_json = {};

    if (texto.includes("---MINUTA---")) {
        const partes = texto.split("---MINUTA---");
        if (partes.length > 1) {
            minuta = partes[1].split("---JSON---")[0].trim();
        }
    } else {
        minuta = texto.split("{")[0].trim();
    }

    try {
        let raw_json_part = "";
        if (texto.includes("```json")) {
            raw_json_part = texto.split("```json")[1].split("```")[0];
        } else if (texto.includes("---JSON---")) {
            raw_json_part = texto.split("---JSON---")[1];
        } else {
            const firstBrace = texto.indexOf("{");
            const lastBrace = texto.lastIndexOf("}");
            if (firstBrace !== -1 && lastBrace !== -1) {
                raw_json_part = texto.substring(firstBrace, lastBrace + 1);
            }
        }

        // LIMPIEZA AGRESIVA DE JSON (Para IA pequeñas como llama3.2)
        // 1. Quitar números de listas estilo 0: "..."
        let clean_json = raw_json_part.replace(/\d+:\s*"/g, '"');
        // 2. Quitar números de objetos estilo 0: {
        clean_json = clean_json.replace(/\d+:\s*{/g, '{');
        // 3. Intentar arreglar comas faltantes entre propiedades (heurística simple)
        clean_json = clean_json.replace(/"\s*"/g, '", "');
        // 4. Quitar caracteres de control
        clean_json = clean_json.trim().replace(/[\x00-\x1F\x7F-\x9F]/g, "");

        datos_json = JSON.parse(clean_json);
    } catch (e) {
        console.log("Error crítico de JSON detectado: ", e);
        datos_json = { 
            error: "La IA generó un formato no estándar", 
            raw_attempt: texto.substring(texto.indexOf("{"), texto.lastIndexOf("}") + 1)
        };
    }

    results.push({
        json: {
            minuta: minuta,
            json: datos_json,
            raw_llm_response: texto
        }
    });
}
return results;
